import{_ as t,o,c as a,a2 as i}from"./chunks/framework.DtwafDNl.js";const p=JSON.parse('{"title":"Your First Call","description":"","frontmatter":{},"headers":[],"relativePath":"guide/first-call.md","filePath":"guide/first-call.md"}'),l={name:"guide/first-call.md"};function n(r,e,s,d,u,h){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="your-first-call" tabindex="-1">Your First Call <a class="header-anchor" href="#your-first-call" aria-label="Permalink to &quot;Your First Call&quot;">​</a></h1><p>This walkthrough creates the smallest useful inbound call path: register a SIP extension, point an inbound DID at a flow, publish <code>Start -&gt; Play Audio -&gt; Hangup</code>, and dial in.</p><ol><li><p>Open the dashboard at <code>http://localhost:3000</code>.</p><p>This is the React dashboard served by the frontend container. Keep the backend running on port <code>3001</code> in the same stack because the dashboard reads and writes configuration through the NestJS API.</p></li><li><p>Go to Configure -&gt; Extensions. Add a new SIP extension — give it a number, a display name, and a password.</p><p>This is the credential your softphone will register with. Use a real password because the extension becomes a SIP identity inside Asterisk.</p></li><li><p>Go to Configure -&gt; Inbound. Create an inbound route — assign a DID number and select a flow.</p><p>If you have no flows yet, leave it and come back after step 5. The DID is the number Asterisk will match when a call enters the system.</p></li><li><p>Go to Configure -&gt; Flow Builder. Create a new flow.</p><p>Drag a Start node, connect it to a Play Audio node, connect that to a Hangup node. Upload or select an audio file for the Play Audio node so the test call has something audible to play.</p></li><li><p>Click Publish.</p><p>The flow is now live — any call hitting the assigned DID will execute it immediately. Draft edits after this point will not affect live calls until you publish again.</p></li><li><p>Register your softphone using the extension credentials and the server IP on port <code>5080</code>.</p><p>Linphone, Zoiper, or any SIP client will work. Dial the DID from the softphone and you should hear your audio file play.</p></li></ol><hr><h2 id="making-an-outbound-call-from-your-softphone" tabindex="-1">Making an outbound call from your softphone <a class="header-anchor" href="#making-an-outbound-call-from-your-softphone" aria-label="Permalink to &quot;Making an outbound call from your softphone&quot;">​</a></h2><p>Callytics supports direct outbound dialing from any registered softphone without using mobile credits. Calls go out through your configured SIP trunk.</p><ol><li><p>Go to Configure -&gt; Trunks. Create a SIP trunk with your provider credentials.</p></li><li><p>Go to Settings and set that trunk as the <strong>default outbound trunk</strong>.</p></li><li><p>Register your softphone to the Callytics server at <code>&lt;host-ip&gt;:5080</code> using an extension credential.</p></li><li><p>From your softphone, dial <code>#</code> followed by the number in international format — for example:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>#94771234567</span></span></code></pre></div><ul><li>Use international format without a leading zero — dial <code>#94771234567</code>, not <code>#0771234567</code></li><li>The <code>#</code> prefix tells Callytics this is a direct outbound dial, not an inbound flow DID</li></ul></li><li><p>You will hear music on hold immediately while Callytics connects the call through your trunk.</p></li><li><p>Go to Call Logs in the dashboard — the call will appear with direction set to <code>outbound</code>.</p></li></ol><blockquote><p>This works over the relay too — your softphone connects to the VPS, dials <code>#NUMBER</code>, and the outbound call goes out through your trunk on the Callytics host. No direct internet path needed from your phone.</p></blockquote>',8)])])}const f=t(l,[["render",n]]);export{p as __pageData,f as default};
